import React, { useState, useEffect } from 'react';
import './LiveUsers.css';

interface LiveUserData {
  timestamp: string;
  count: number;
}

const LiveUsers: React.FC = () => {
  const [liveCount, setLiveCount] = useState(1247);
  const [chartData, setChartData] = useState<LiveUserData[]>([]);

  // Generate mock real-time data
  useEffect(() => {
    const generateInitialData = () => {
      const data: LiveUserData[] = [];
      const now = new Date();

      for (let i = 23; i >= 0; i--) {
        const time = new Date(now.getTime() - i * 60 * 60 * 1000);
        data.push({
          timestamp: time.toISOString(),
          count: Math.floor(Math.random() * 500) + 800
        });
      }
      return data;
    };

    setChartData(generateInitialData());

    // Simulate real-time updates
    const interval = setInterval(() => {
      const newCount = Math.floor(Math.random() * 200) + 1150;
      setLiveCount(newCount);

      setChartData(prev => {
        const newData = [...prev.slice(1)];
        newData.push({
          timestamp: new Date().toISOString(),
          count: newCount
        });
        return newData;
      });
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  const maxValue = Math.max(...chartData.map(d => d.count));
  const minValue = Math.min(...chartData.map(d => d.count));

  return (
    <div className="live-users-container">
      <div className="live-users-header">
        <div className="header-content">
          <h2>Live Users</h2>
          <div className="live-indicator">
            <div className="live-dot"></div>
            <span>Live</span>
          </div>
        </div>
        <div className="live-count">
          <span className="count-number">{liveCount.toLocaleString()}</span>
          <span className="count-label">Active Users</span>
        </div>
      </div>

      <div className="chart-container">
        <div className="chart-wrapper">
          <svg className="live-chart" viewBox="0 0 800 200">
            <defs>
              <linearGradient id="liveGradient" x1="0%" y1="0%" x2="0%" y2="100%">
                <stop offset="0%" stopColor="#10b981" stopOpacity="0.3"/>
                <stop offset="100%" stopColor="#10b981" stopOpacity="0.05"/>
              </linearGradient>
            </defs>

            {/* Grid lines */}
            {[0, 1, 2, 3, 4].map(i => (
              <line
                key={i}
                x1="0"
                y1={i * 40}
                x2="800"
                y2={i * 40}
                stroke="#e5e7eb"
                strokeWidth="1"
                opacity="0.5"
              />
            ))}

            {/* Chart area */}
            {chartData.length > 1 && (
              <>
                <path
                  d={`M ${chartData.map((d, i) => 
                    `${(i / (chartData.length - 1)) * 800},${200 - ((d.count - minValue) / (maxValue - minValue)) * 160}`
                  ).join(' L ')}`}
                  fill="none"
                  stroke="#10b981"
                  strokeWidth="3"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />

                <path
                  d={`M ${chartData.map((d, i) => 
                    `${(i / (chartData.length - 1)) * 800},${200 - ((d.count - minValue) / (maxValue - minValue)) * 160}`
                  ).join(' L ')} L 800,200 L 0,200 Z`}
                  fill="url(#liveGradient)"
                />
              </>
            )}

            {/* Data points */}
            {chartData.map((d, i) => (
              <circle
                key={i}
                cx={(i / (chartData.length - 1)) * 800}
                cy={200 - ((d.count - minValue) / (maxValue - minValue)) * 160}
                r="4"
                fill="#10b981"
                className="data-point"
              />
            ))}
          </svg>
        </div>

        <div className="chart-labels">
          <div className="time-labels">
            {chartData.filter((_, i) => i % 4 === 0).map((d, i) => (
              <span key={i} className="time-label">
                {new Date(d.timestamp).toLocaleTimeString('en-US', { 
                  hour: '2-digit', 
                  minute: '2-digit',
                  hour12: false 
                })}
              </span>
            ))}
          </div>
        </div>
      </div>

      <div className="live-stats">
        <div className="stat-item">
          <span className="stat-label">Peak Today</span>
          <span className="stat-value">{Math.max(...chartData.map(d => d.count)).toLocaleString()}</span>
        </div>
        <div className="stat-item">
          <span className="stat-label">Average</span>
          <span className="stat-value">
            {Math.round(chartData.reduce((sum, d) => sum + d.count, 0) / chartData.length).toLocaleString()}
          </span>
        </div>
        <div className="stat-item">
          <span className="stat-label">Low Today</span>
          <span className="stat-value">{Math.min(...chartData.map(d => d.count)).toLocaleString()}</span>
        </div>
      </div>
    </div>
  );
};

export default LiveUsers;
